13→describe('containers repository', () => {
14→	let db: Database.Database;
15→
16→	beforeEach(() => {
17→		db = new Database(':memory:');
18→		runMigrations(db);
19→	});
20→
21→	it('creates a container and returns it', () => {
22→		const container = createContainer(db, {
23→			id: 'c1',
24→			name: 'my-container',
25→			template_id: 'rust',
26→			config: { image: 'rust:latest' }
27→		});
28→		expect(container.id).toBe('c1');
29→		expect(container.name).toBe('my-container');
30→		expect(container.status).toBe('stopped');
31→	});
32→
33→	it('gets a container by id', () => {
34→		createContainer(db, { id: 'c2', name: 'foo', template_id: 'blank', config: {} });
35→		const found = getContainerById(db, 'c2');
36→		expect(found).not.toBeNull();
37→		expect(found!.name).toBe('foo');
38→	});
39→
40→	it('returns null for unknown id', () => {
41→		expect(getContainerById(db, 'nope')).toBeNull();
42→	});
43→
44→	it('gets all containers', () => {
45→		createContainer(db, { id: 'c3', name: 'a', template_id: 'blank', config: {} });
46→		createContainer(db, { id: 'c4', name: 'b', template_id: 'blank', config: {} });
47→		const all = getAllContainers(db);
48→		expect(all.length).toBe(2);
49→	});
50→
51→	it('updates a container', () => {
52→		createContainer(db, { id: 'c5', name: 'upd', template_id: 'blank', config: {} });
53→		updateContainer(db, 'c5', { status: 'running' });
54→		const updated = getContainerById(db, 'c5');
55→		expect(updated!.status).toBe('running');
56→	});
57→
58→	it('deletes a container', () => {
59→		createContainer(db, { id: 'c6', name: 'del', template_id: 'blank', config: {} });
60→		deleteContainer(db, 'c6');
